mapper.select:
SELECT id, work_record_id, expense_type, amount, description, expense_time
FROM work_record_expense
WHERE id = #{id}

SELECT
    wre.expense_type,
    SUM(wre.amount) AS totalAmount
FROM work_record_expense wre
LEFT JOIN work_record wr ON wre.work_record_id = wr.id

    wr.user_id = #{userId}
    AND wr.deleted = 0
    AND wre.expense_time >= #{expenseTimeFrom}
    AND wre.expense_time <= #{expenseTimeTo}

GROUP BY wre.expense_type

mapper.update:
UPDATE work_record_expense
expense_type = #{expenseType}, amount = #{amount}, description = #{description}, expense_time = #{expenseTime},
WHERE id = #{id}
